import { useState, useEffect, useRef, useCallback } from "react";

const AERIAL_IMG = "data:image/jpeg;base64,";


const ZONES = [
  { id:"A1", label:"Tank Farm A", x:18, y:14, desc:"4 storage tanks — Methanol / Ethanol" },
  { id:"A2", label:"Tank Farm B", x:75, y:14, desc:"4 storage tanks — Sulfuric Acid / NaOH" },
  { id:"B1", label:"Pipe Corridor", x:48, y:40, desc:"Main transfer pipeline network" },
  { id:"C1", label:"Unload Bay C-7", x:22, y:80, desc:"Active: Tanker 沪A-38927 — Methanol" },
  { id:"C2", label:"Unload Bay C-8", x:60, y:82, desc:"Active: Tanker 京B-10234 — NaOH" },
  { id:"D1", label:"Control Bldg", x:12, y:48, desc:"Operations center + Lab" },
];

function genCurve(base,v,len,aAt,aSize){
  const p=[];let val=base;
  for(let i=0;i<len;i++){
    val+=(Math.random()-.5)*v;val=val*.97+base*.03;
    if(aAt&&i>=aAt&&i<aAt+8) p.push(val+Math.sin(((i-aAt)/8)*Math.PI)*aSize);
    else p.push(val);
  }return p;
}

const LEN=100;
const ZD={
  "C1":{
    normal:{pressure:genCurve(1.8,.04,LEN),temp:genCurve(23,.3,LEN),flow:genCurve(120,1.5,LEN),gas:genCurve(4,.3,LEN)},
    anomaly:{pressure:genCurve(1.8,.04,LEN,60,-1.3),temp:genCurve(23,.3,LEN,68,18),flow:genCurve(120,1.5,LEN,55,-85),gas:genCurve(4,.3,LEN,50,22)},
  },
  "C2":{
    normal:{pressure:genCurve(2.1,.03,LEN),temp:genCurve(25,.2,LEN),flow:genCurve(95,1,LEN),gas:genCurve(3,.2,LEN)},
    anomaly:{pressure:genCurve(2.1,.03,LEN),temp:genCurve(25,.2,LEN,65,8),flow:genCurve(95,1,LEN,60,-30),gas:genCurve(3,.2,LEN,55,9)},
  },
  _def:{
    normal:{pressure:genCurve(1.5,.02,LEN),temp:genCurve(22,.15,LEN),flow:genCurve(0,0,LEN),gas:genCurve(2,.1,LEN)},
    anomaly:{pressure:genCurve(1.5,.02,LEN,70,.4),temp:genCurve(22,.15,LEN),flow:genCurve(0,0,LEN),gas:genCurve(2,.1,LEN,68,4)},
  },
};

const SIGS=[
  {key:"pressure",label:"PRESSURE",unit:"MPa",color:"#00e6a0",wH:2.5,wL:0.8,dec:2},
  {key:"temp",label:"TEMPERATURE",unit:"°C",color:"#0099ff",wH:38,wL:null,dec:1},
  {key:"flow",label:"FLOW RATE",unit:"L/min",color:"#00d4aa",wH:null,wL:50,dec:1},
  {key:"gas",label:"GAS CONC.",unit:"ppm",color:"#a78bfa",wH:15,wL:null,dec:1},
];

const LOGS_TL=[
  {t:50,msg:"Zone C-7: Gas concentration rising — 4.2→8.7 ppm",lv:"WARN"},
  {t:53,msg:"Zone C-7: Gas threshold exceeded — 15.3 ppm",lv:"ALERT"},
  {t:55,msg:"Zone C-7: Flow rate dropping — 120→78 L/min",lv:"WARN"},
  {t:58,msg:"Zone C-7: Flow critical — 42 L/min",lv:"ALERT"},
  {t:60,msg:"Zone C-7: Pressure anomaly — 1.8→0.6 MPa",lv:"ALERT"},
  {t:62,msg:"AI: Pressure-flow mismatch → Leak at Node A3",lv:"CRITICAL"},
  {t:65,msg:"Zone C-7: Auto-shutoff Valve C-23 triggered",lv:"CRITICAL"},
  {t:68,msg:"Zone C-7: Temp spike 23→38°C — Reaction risk",lv:"ALERT"},
  {t:70,msg:"DISPATCH: Response team → Zone C-7 — ETA 4min",lv:"CRITICAL"},
];

// Preset chat responses based on keywords + context
function getPresetReply(input, zone, mode, risk, sigs, tick) {
  const q = input.toLowerCase();
  const zInfo = ZONES.find(z=>z.id===zone);
  const zName = zInfo?.label || zone;
  const zDesc = zInfo?.desc || "";

  // Status queries
  if (q.includes("status") || q.includes("情况") || q.includes("怎么样") || q.includes("report") || q.includes("状态")) {
    if (risk === "HIGH") {
      return `⚠ ${zName} is in CRITICAL state. Pressure at ${sigs[0].toFixed(2)} MPa (below safe threshold), gas concentration elevated at ${sigs[3].toFixed(1)} ppm. Flow rate has dropped to ${sigs[2].toFixed(1)} L/min. Multi-signal anomaly detected — leak suspected at Node A3. Immediate intervention required.`;
    }
    if (risk === "MEDIUM") {
      return `⚡ ${zName} showing elevated readings. Gas concentration at ${sigs[3].toFixed(1)} ppm (trending up), flow rate fluctuating at ${sigs[2].toFixed(1)} L/min. Recommend increased monitoring frequency and standby for contingency.`;
    }
    return `✅ ${zName} operating normally. Pressure: ${sigs[0].toFixed(2)} MPa, Temp: ${sigs[1].toFixed(1)}°C, Flow: ${sigs[2].toFixed(1)} L/min, Gas: ${sigs[3].toFixed(1)} ppm. All parameters within safe range. ${zDesc}`;
  }

  // Leak queries
  if (q.includes("leak") || q.includes("泄漏") || q.includes("漏")) {
    if (risk === "HIGH") {
      return `🚨 Leak confirmed at ${zName}, Node A3. Evidence: pressure dropped 78% in 22s, gas concentration spiked to ${sigs[3].toFixed(1)} ppm, liquid pooling detected on ground surface (~2.1m²). Valve C-23 auto-shutoff triggered. Response team dispatched, ETA 4 minutes.`;
    }
    return `No leak indicators detected at ${zName}. Pressure stable at ${sigs[0].toFixed(2)} MPa, gas concentration nominal at ${sigs[3].toFixed(1)} ppm. Continuous monitoring active.`;
  }

  // Valve control
  if (q.includes("valve") || q.includes("阀") || q.includes("关阀") || q.includes("close") || q.includes("shut")) {
    if (risk === "HIGH") {
      return `Valve C-23 has been auto-closed by the emergency protocol at ${zName}. Current valve state: CLOSED. Pressure equalizing — currently at ${sigs[0].toFixed(2)} MPa. Do not reopen until inspection team confirms seal integrity.`;
    }
    return `Valve C-23 at ${zName} is currently OPEN — correct position for active transfer. Flow rate: ${sigs[2].toFixed(1)} L/min. No reason to close at this time. Shall I schedule a valve inspection?`;
  }

  // Temperature
  if (q.includes("temp") || q.includes("温度") || q.includes("heat") || q.includes("hot")) {
    if (sigs[1] > 35) {
      return `⚠ Temperature alert at ${zName}: ${sigs[1].toFixed(1)}°C — above normal range (18-32°C). Possible exothermic reaction risk. Recommend activating cooling system and halting transfer until stabilized.`;
    }
    return `Temperature at ${zName}: ${sigs[1].toFixed(1)}°C — within normal operating range. Ambient conditions stable. No cooling intervention needed.`;
  }

  // Pressure
  if (q.includes("pressure") || q.includes("压力")) {
    if (sigs[0] < 0.8) {
      return `🚨 Pressure critically low at ${zName}: ${sigs[0].toFixed(2)} MPa (threshold: 0.8 MPa). This correlates with flow rate anomaly — likely indicates transfer line breach. Emergency shutoff recommended.`;
    }
    return `Pressure at ${zName}: ${sigs[0].toFixed(2)} MPa — within normal range (0.8–2.5 MPa). Stable over last 60 seconds. No intervention needed.`;
  }

  // Gas
  if (q.includes("gas") || q.includes("气体") || q.includes("浓度") || q.includes("ppm")) {
    if (sigs[3] > 15) {
      return `🚨 Gas concentration CRITICAL at ${zName}: ${sigs[3].toFixed(1)} ppm (safe limit: 15 ppm). H₂S detected. Immediate evacuation of 50m radius required. Scrubber system activation recommended.`;
    }
    if (sigs[3] > 8) {
      return `⚡ Gas concentration elevated at ${zName}: ${sigs[3].toFixed(1)} ppm — approaching threshold (15 ppm). Trend: rising. Recommend dispatching UAV for close-range inspection at transfer junction.`;
    }
    return `Gas concentration at ${zName}: ${sigs[3].toFixed(1)} ppm — well within safe limits (threshold: 15 ppm). Air quality nominal.`;
  }

  // Flow
  if (q.includes("flow") || q.includes("流量") || q.includes("传输")) {
    if (sigs[2] < 50) {
      return `⚠ Flow rate critically low at ${zName}: ${sigs[2].toFixed(1)} L/min (expected: ~120 L/min). Possible blockage or line rupture. Cross-referencing with pressure data suggests leak scenario.`;
    }
    return `Flow rate at ${zName}: ${sigs[2].toFixed(1)} L/min — matching target rate of 120 L/min. Transfer proceeding normally. Estimated completion: 23 minutes.`;
  }

  // Evacuation
  if (q.includes("evacuat") || q.includes("撤离") || q.includes("疏散")) {
    if (risk === "HIGH") {
      return `🚷 Evacuation order ACTIVE for ${zName}. All personnel must move to 50m safe perimeter. 2 operators were in zone — confirmed evacuating. Response team inbound, ETA 4 minutes. Wind direction: NE 3.2 m/s — downwind areas also flagged.`;
    }
    return `No evacuation necessary. ${zName} operating normally. Emergency routes verified — Exit A (north) and Exit B (east) are clear.`;
  }

  // Dispatch / response team
  if (q.includes("dispatch") || q.includes("team") || q.includes("响应") || q.includes("调度") || q.includes("应急")) {
    if (risk === "HIGH") {
      return `Emergency response already dispatched to ${zName}. Team composition: 4 hazmat technicians + 1 supervisor. Equipment: gas scrubber, spill containment kit, portable detector array. ETA: 3 minutes. UAV-07 maintaining overhead surveillance.`;
    }
    return `No emergency dispatch needed. All zones nominal. Routine patrol schedule: UAV-07 next flyover of ${zName} in 8 minutes.`;
  }

  // UAV / drone
  if (q.includes("uav") || q.includes("drone") || q.includes("无人机")) {
    return `UAV-07 currently assigned to ${zName}, altitude 25m AGL. Battery: 78%. Signal: strong. Sensors active: RGB camera, thermal imager, gas detector. Next scheduled rotation: UAV-12 takes over in 42 minutes.`;
  }

  // Zone specific
  if (q.includes("c-7") || q.includes("c7")) {
    return mode === "anomaly" && tick > 50
      ? `⚠ Zone C-7 (Unload Bay) is in ALERT state. Active leak detected at methanol transfer junction. Valve C-23 auto-closed. Area under evacuation. Response team inbound.`
      : `Zone C-7 (Unload Bay): Active methanol transfer from Tanker 沪A-38927. All readings nominal. Operator ZHANG W. on site with valid work permit.`;
  }
  if (q.includes("c-8") || q.includes("c8")) {
    return `Zone C-8 (Unload Bay): Active NaOH transfer from Tanker 京B-10234. Pressure: 2.1 MPa, flow: 95 L/min. All nominal. No anomalies detected.`;
  }

  // Recommendation
  if (q.includes("recommend") || q.includes("suggest") || q.includes("建议") || q.includes("怎么办") || q.includes("what should")) {
    if (risk === "HIGH") {
      return `Recommended actions for ${zName}:\n1. Confirm valve C-23 is sealed\n2. Maintain 50m evacuation perimeter\n3. Deploy gas scrubber at Node A3\n4. Monitor wind direction for vapor drift\n5. Prepare decontamination equipment\n6. Document incident for regulatory report`;
    }
    if (risk === "MEDIUM") {
      return `Recommended actions for ${zName}:\n1. Increase UAV monitoring frequency to 30s intervals\n2. Alert standby response team\n3. Verify all PPE compliance\n4. Prepare contingency shutoff procedure\n5. Continue monitoring — escalate if gas exceeds 15 ppm`;
    }
    return `${zName} operating normally. No special actions needed. Routine recommendations: maintain scheduled UAV patrol, verify PPE compliance at shift change, confirm emergency equipment inspection is current.`;
  }

  // Help
  if (q.includes("help") || q.includes("帮助") || q.includes("what can") || q.includes("你能")) {
    return `I can help you with:\n• Zone status reports ("C-7 status")\n• Specific readings ("pressure", "temperature", "gas level", "flow rate")\n• Leak assessment ("any leaks?")\n• Valve control ("close valve")\n• Evacuation status ("evacuation report")\n• Dispatch info ("response team status")\n• UAV status ("drone report")\n• Recommendations ("what should we do?")\n\nTry asking in English or Chinese.`;
  }

  // Default
  if (risk === "HIGH") {
    return `⚠ Alert: ${zName} is currently in HIGH risk state. Leak detected, emergency protocols active. Please specify what information you need — status, valve control, evacuation, or recommendations.`;
  }
  return `${zName} is operating normally. All 4 signal parameters within safe range. Ask me about specific readings, zone status, or recommendations. Type "help" for available commands.`;
}

function Glass({children,style}){
  return <div style={{background:"rgba(8,14,22,0.9)",backdropFilter:"blur(14px)",border:"1px solid rgba(80,200,170,0.1)",borderRadius:8,boxShadow:"0 4px 28px rgba(0,0,0,0.5), inset 0 1px 0 rgba(255,255,255,0.02)",...style}}>{children}</div>;
}

function MiniCurve({data,visEnd,color,wH,wL,w,h}){
  const s=Math.max(0,visEnd-40),vis=data.slice(s,visEnd);
  if(vis.length<2)return null;
  const mn=Math.min(...data)-(Math.max(...data)-Math.min(...data))*.15,mx=Math.max(...data)+(Math.max(...data)-Math.min(...data))*.15,rng=mx-mn||1;
  const pts=vis.map((v,i)=>`${(i/(vis.length-1))*w},${h-((v-mn)/rng)*h}`).join(" ");
  const hasA=vis.some(v=>(wH&&v>wH)||(wL&&v<wL));
  const lc=hasA?"#ff3c3c":color;
  const gid=`mc${color.replace("#","")}-${Math.random().toString(36).slice(2,6)}`;
  return(
    <svg width={w} height={h} viewBox={`0 0 ${w} ${h}`} style={{display:"block"}}>
      <defs>
        <linearGradient id={gid} x1="0" y1="0" x2="0" y2="1"><stop offset="0%" stopColor={lc} stopOpacity=".12"/><stop offset="100%" stopColor={lc} stopOpacity="0"/></linearGradient>
        <filter id={`g${gid}`}><feGaussianBlur stdDeviation="1.5"/><feMerge><feMergeNode/><feMergeNode in="SourceGraphic"/></feMerge></filter>
      </defs>
      {wH&&<line x1="0" y1={h-((wH-mn)/rng)*h} x2={w} y2={h-((wH-mn)/rng)*h} stroke="#ff3c3c" strokeWidth=".5" strokeDasharray="3 3" opacity=".3"/>}
      {wL&&<line x1="0" y1={h-((wL-mn)/rng)*h} x2={w} y2={h-((wL-mn)/rng)*h} stroke="#ff3c3c" strokeWidth=".5" strokeDasharray="3 3" opacity=".3"/>}
      <polygon points={`0,${h} ${pts} ${w},${h}`} fill={`url(#${gid})`}/>
      <polyline points={pts} fill="none" stroke={lc} strokeWidth="1.5" strokeLinejoin="round" filter={`url(#g${gid})`}/>
      <circle cx={w} cy={h-((vis[vis.length-1]-mn)/rng)*h} r="2.5" fill={lc} opacity=".8"/>
    </svg>
  );
}

function ZoneMarker({zone,selected,onClick,level}){
  const colors={ok:"#00e6a0",warn:"#ffaa00",alert:"#ff3c3c"};
  const c=colors[level]||(selected?"#00e6a0":"rgba(0,230,160,0.6)");
  const isAlert=level==="alert";
  const isWarn=level==="warn";
  return(
    <div onClick={onClick} style={{position:"absolute",left:`${zone.x}%`,top:`${zone.y}%`,transform:"translate(-50%,-50%)",zIndex:20,cursor:"pointer",textAlign:"center"}}>
      <div style={{width:selected?16:12,height:selected?16:12,borderRadius:"50%",background:c,boxShadow:`0 0 ${isAlert?20:isWarn?14:10}px ${c}`,margin:"0 auto",border:selected?"2px solid #fff":"none",transition:"all .3s",animation:isAlert?"zP 1s ease-in-out infinite":isWarn?"zPW 1.5s ease-in-out infinite":"none"}}/>
      <div style={{marginTop:4,fontSize:8,fontWeight:700,color:"#fff",letterSpacing:1,textShadow:"0 1px 6px rgba(0,0,0,0.8)",whiteSpace:"nowrap",background:"rgba(0,0,0,0.5)",padding:"1px 6px",borderRadius:3,border:`1px solid ${c}44`}}>{zone.label}</div>
    </div>
  );
}

export default function DashboardV2(){
  const[mode,setMode]=useState("normal");
  const[selZone,setSelZone]=useState("C1");
  const[tick,setTick]=useState(0);
  const[logs,setLogs]=useState([]);
  const[paused,setPaused]=useState(false);
  const[chatInput,setChatInput]=useState("");
  const[chatMsgs,setChatMsgs]=useState([{role:"ai",text:"System online. Monitoring 6 zones across the chemical park. All parameters nominal. How can I assist you? Type 'help' for available commands."}]);
  const tickRef=useRef(0);
  const chatEndRef=useRef(null);

  const zd=ZD[selZone]||ZD._def;
  const curData=mode==="anomaly"?zd.anomaly:zd.normal;
  const visEnd=Math.min(tick,LEN);

  const getVal=(key)=>curData[key][Math.max(0,Math.min(visEnd,LEN-1))];
  const getSt=(sig)=>{
    const v=getVal(sig.key);
    if(sig.wH&&v>sig.wH)return{label:"CRITICAL",color:"#ff3c3c"};
    if(sig.wL&&v<sig.wL)return{label:"CRITICAL",color:"#ff3c3c"};
    if(sig.wH&&v>sig.wH*.85)return{label:"ELEVATED",color:"#ffaa00"};
    if(sig.wL&&v<sig.wL*1.3)return{label:"LOW",color:"#ffaa00"};
    return{label:"NORMAL",color:"#00e6a0"};
  };

  const allSt=SIGS.map(s=>({...s,st:getSt(s)}));
  const hasAlert=allSt.some(s=>s.st.color==="#ff3c3c");
  const hasWarn=allSt.some(s=>s.st.color==="#ffaa00");
  const risk=hasAlert?"HIGH":hasWarn?"MEDIUM":"LOW";
  const rc=hasAlert?"#ff3c3c":hasWarn?"#ffaa00":"#00e6a0";

  useEffect(()=>{
    if(paused)return;
    const iv=setInterval(()=>{
      tickRef.current+=1;setTick(tickRef.current);
      if(mode==="anomaly"){
        LOGS_TL.forEach(l=>{if(tickRef.current===l.t)setLogs(prev=>[{...l,time:new Date().toTimeString().slice(0,8)},...prev].slice(0,15));});
      }
    },500);
    return()=>clearInterval(iv);
  },[paused,mode]);

  const reset=(m)=>{tickRef.current=0;setTick(0);setLogs([]);setMode(m);setChatMsgs([{role:"ai",text:m==="anomaly"?"Switching to ANOMALY simulation. Monitoring for developing threats across all zones...":"System reset. All zones nominal. How can I assist?"}]);};

  const sendChat=useCallback(()=>{
    if(!chatInput.trim())return;
    const userMsg=chatInput.trim();
    setChatInput("");
    setChatMsgs(prev=>[...prev,{role:"user",text:userMsg}]);

    const sigVals=[getVal("pressure"),getVal("temp"),getVal("flow"),getVal("gas")];
    const reply=getPresetReply(userMsg,selZone,mode,risk,sigVals,tick);

    setTimeout(()=>{
      setChatMsgs(prev=>[...prev,{role:"ai",text:reply}]);
    },600+Math.random()*800);
  },[chatInput,selZone,mode,risk,tick]);

  useEffect(()=>{chatEndRef.current?.scrollIntoView({behavior:"smooth"})},[chatMsgs]);

  return(
    <div style={{width:"100%",height:"100vh",position:"relative",overflow:"hidden",fontFamily:"'PingFang SC','Helvetica Neue',Arial,sans-serif",userSelect:"none",background:"linear-gradient(135deg,#060a14,#0a1020,#080e1a)"}}>
      <style>{`
        @keyframes fI{from{opacity:0;transform:translateY(4px)}to{opacity:1;transform:translateY(0)}}
        @keyframes zP{0%,100%{box-shadow:0 0 12px rgba(255,60,60,0.4)}50%{box-shadow:0 0 28px rgba(255,60,60,0.7)}}
        @keyframes zPW{0%,100%{box-shadow:0 0 8px rgba(255,170,0,0.3)}50%{box-shadow:0 0 22px rgba(255,170,0,0.6)}}
        @keyframes rP{0%,100%{opacity:1}50%{opacity:.5}}
        @keyframes aF{0%,100%{border-color:rgba(255,60,60,0.4)}50%{border-color:rgba(255,60,60,0.08)}}
        @keyframes logS{from{opacity:0;transform:translateX(-8px)}to{opacity:1;transform:translateX(0)}}
        @keyframes dotB{0%,100%{opacity:.8}50%{opacity:.2}}
        @keyframes typeIn{from{opacity:0;transform:translateY(4px)}to{opacity:1;transform:translateY(0)}}
      `}</style>

      <div style={{position:"absolute",inset:0,backgroundImage:"linear-gradient(rgba(0,230,160,0.015) 1px,transparent 1px),linear-gradient(90deg,rgba(0,230,160,0.015) 1px,transparent 1px)",backgroundSize:"50px 50px"}}/>

      {/* TOP BAR */}
      <div style={{position:"absolute",top:0,left:0,right:0,height:44,background:"rgba(0,0,0,0.45)",borderBottom:`1px solid ${rc}12`,display:"flex",alignItems:"center",justifyContent:"space-between",padding:"0 20px",zIndex:30}}>
        <div style={{display:"flex",alignItems:"center",gap:12}}>
          <div style={{width:7,height:7,borderRadius:"50%",background:rc,boxShadow:`0 0 8px ${rc}`,animation:hasAlert?"rP 1s ease-in-out infinite":"none"}}/>
          <span style={{fontSize:10,letterSpacing:3,color:"rgba(255,255,255,.45)",fontWeight:600}}>PARK INTELLIGENT MONITORING CENTER</span>
        </div>
        <div style={{display:"flex",gap:8}}>
          <button onClick={()=>reset("normal")} style={{padding:"4px 12px",borderRadius:4,fontSize:8,fontWeight:700,letterSpacing:1.5,cursor:"pointer",background:mode==="normal"?"rgba(0,230,160,.12)":"rgba(255,255,255,.04)",border:`1px solid ${mode==="normal"?"rgba(0,230,160,.25)":"rgba(255,255,255,.08)"}`,color:mode==="normal"?"#00e6a0":"rgba(255,255,255,.35)",fontFamily:"inherit"}}>NORMAL</button>
          <button onClick={()=>reset("anomaly")} style={{padding:"4px 12px",borderRadius:4,fontSize:8,fontWeight:700,letterSpacing:1.5,cursor:"pointer",background:mode==="anomaly"?"rgba(255,60,60,.12)":"rgba(255,255,255,.04)",border:`1px solid ${mode==="anomaly"?"rgba(255,60,60,.25)":"rgba(255,255,255,.08)"}`,color:mode==="anomaly"?"#ff3c3c":"rgba(255,255,255,.35)",fontFamily:"inherit"}}>ANOMALY</button>
          <button onClick={()=>setPaused(!paused)} style={{padding:"4px 12px",borderRadius:4,fontSize:8,fontWeight:700,cursor:"pointer",background:"rgba(255,255,255,.06)",border:"1px solid rgba(255,255,255,.1)",color:"rgba(255,255,255,.4)",fontFamily:"inherit"}}>{paused?"▶":"⏸"}</button>
        </div>
      </div>

      {/* MAIN */}
      <div style={{position:"absolute",top:52,left:14,right:14,bottom:110,display:"flex",gap:10,zIndex:10}}>

        {/* LEFT */}
        <div style={{flex:1,display:"flex",flexDirection:"column",gap:10}}>
          {/* Map */}
          <Glass style={{flex:1,position:"relative",overflow:"hidden",padding:0}}>
            <div style={{position:"absolute",inset:0,backgroundImage:`url(${AERIAL_IMG})`,backgroundSize:"cover",backgroundPosition:"center",opacity:.85}}/>
            <div style={{position:"absolute",inset:0,background:"rgba(0,0,0,0.25)"}}/>
            {ZONES.map(z=>(
              <ZoneMarker key={z.id} zone={z} selected={selZone===z.id} onClick={()=>setSelZone(z.id)}
                level={(() => {
                const zData = ZD[z.id] || ZD._def;
                const d = mode === "anomaly" ? zData.anomaly : zData.normal;
                const idx = Math.max(0, Math.min(visEnd, LEN-1));
                const p = d.pressure[idx], t = d.temp[idx], fl = d.flow[idx], g = d.gas[idx];
                if (p < 0.8 || p > 2.5 || t > 38 || fl < 50 || g > 15) return "alert";
                if (p < 1.0 || p > 2.2 || t > 32 || (fl > 0 && fl < 80) || g > 8) return "warn";
                return "ok";
              })()}/>
            ))}
            <div style={{position:"absolute",top:8,left:10,fontSize:8,fontWeight:700,color:"rgba(255,255,255,.5)",letterSpacing:2,background:"rgba(0,0,0,.4)",padding:"3px 8px",borderRadius:3}}>PARK OVERVIEW — LIVE</div>
            <div style={{position:"absolute",bottom:8,right:10,fontSize:7,color:"rgba(255,255,255,.3)",letterSpacing:1}}>Selected: {ZONES.find(z=>z.id===selZone)?.label}</div>
          </Glass>

          {/* Curves */}
          <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,flexShrink:0,height:180}}>
            {SIGS.map(sig=>{
              const v=getVal(sig.key);const st=getSt(sig);const isA=st.color==="#ff3c3c";
              return(
                <Glass key={sig.key} style={{padding:"10px 12px",display:"flex",flexDirection:"column",borderColor:isA?"rgba(255,60,60,.15)":"rgba(80,200,170,.08)"}}>
                  <div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-start",marginBottom:4}}>
                    <div>
                      <div style={{fontSize:7,color:"rgba(255,255,255,.3)",letterSpacing:1.5,fontWeight:600}}>{sig.label}</div>
                      <div style={{display:"flex",alignItems:"baseline",gap:3}}>
                        <span style={{fontSize:22,fontWeight:800,color:st.color,transition:"color .3s"}}>{v.toFixed(sig.dec)}</span>
                        <span style={{fontSize:9,color:"rgba(255,255,255,.25)"}}>{sig.unit}</span>
                      </div>
                    </div>
                    <div style={{padding:"2px 7px",borderRadius:2,background:`${st.color}12`,border:`1px solid ${st.color}25`,fontSize:7,fontWeight:700,color:st.color,letterSpacing:1,animation:isA?"rP 1s ease-in-out infinite":"none"}}>{st.label}</div>
                  </div>
                  <div style={{flex:1,minHeight:0}}>
                    <MiniCurve data={curData[sig.key]} visEnd={visEnd} color={sig.color} wH={sig.wH} wL={sig.wL} w={260} h={65}/>
                  </div>
                </Glass>
              );
            })}
          </div>
        </div>

        {/* RIGHT */}
        <div style={{width:280,display:"flex",flexDirection:"column",gap:10}}>
          {/* Status */}
          <Glass style={{padding:"12px 14px",flexShrink:0}}>
            <div style={{fontSize:8,fontWeight:700,color:"rgba(255,255,255,.4)",letterSpacing:2,marginBottom:8}}>ZONE STATUS — {selZone}</div>
            {allSt.map(s=>(
              <div key={s.key} style={{display:"flex",justifyContent:"space-between",alignItems:"center",padding:"5px 0",borderBottom:"1px solid rgba(255,255,255,.03)"}}>
                <div style={{display:"flex",alignItems:"center",gap:6}}>
                  <div style={{width:5,height:5,borderRadius:"50%",background:s.st.color,boxShadow:`0 0 4px ${s.st.color}`}}/>
                  <span style={{fontSize:9,color:"rgba(255,255,255,.5)"}}>{s.label}</span>
                </div>
                <span style={{fontSize:9,fontWeight:700,color:s.st.color,letterSpacing:1}}>{s.st.label}</span>
              </div>
            ))}
            <div style={{marginTop:8,padding:"8px",borderRadius:4,background:`${rc}10`,border:`1px solid ${rc}20`,textAlign:"center",transition:"all .5s"}}>
              <div style={{fontSize:7,color:"rgba(255,255,255,.25)",letterSpacing:1.5}}>RISK LEVEL</div>
              <div style={{fontSize:18,fontWeight:900,color:rc,letterSpacing:2,animation:hasAlert?"rP 1s ease-in-out infinite":"none"}}>{risk}</div>
            </div>
          </Glass>

          {/* AI Agent Chat */}
          <Glass style={{flex:1,padding:"12px 14px",display:"flex",flexDirection:"column",overflow:"hidden"}}>
            <div style={{fontSize:8,fontWeight:700,color:"rgba(255,255,255,.4)",letterSpacing:2,marginBottom:8,flexShrink:0}}>AI MONITORING AGENT</div>
            <div style={{flex:1,overflowY:"auto",marginBottom:8}}>
              {chatMsgs.map((m,i)=>(
                <div key={i} style={{marginBottom:8,display:"flex",flexDirection:"column",alignItems:m.role==="user"?"flex-end":"flex-start",animation:"typeIn .4s ease"}}>
                  <div style={{
                    maxWidth:"92%",padding:"8px 11px",borderRadius:m.role==="user"?"8px 8px 2px 8px":"8px 8px 8px 2px",
                    background:m.role==="user"?"rgba(0,150,255,.12)":"rgba(0,230,160,.06)",
                    border:`1px solid ${m.role==="user"?"rgba(0,150,255,.18)":"rgba(0,230,160,.1)"}`,
                  }}>
                    <div style={{fontSize:9.5,color:"rgba(255,255,255,.7)",lineHeight:1.6,whiteSpace:"pre-line"}}>{m.text}</div>
                  </div>
                </div>
              ))}
              <div ref={chatEndRef}/>
            </div>
            <div style={{display:"flex",gap:6,flexShrink:0}}>
              <input value={chatInput} onChange={e=>setChatInput(e.target.value)}
                onKeyDown={e=>e.key==="Enter"&&sendChat()}
                placeholder="Ask about any zone..."
                style={{flex:1,padding:"8px 10px",borderRadius:5,border:"1px solid rgba(255,255,255,.1)",background:"rgba(255,255,255,.04)",color:"#fff",fontSize:10,outline:"none",fontFamily:"inherit"}}/>
              <button onClick={sendChat} style={{
                padding:"8px 14px",borderRadius:5,background:"rgba(0,230,160,.15)",border:"1px solid rgba(0,230,160,.25)",
                color:"#00e6a0",fontSize:9,fontWeight:700,cursor:"pointer",fontFamily:"inherit",letterSpacing:1,
              }}>SEND</button>
            </div>
          </Glass>
        </div>
      </div>

      {/* BOTTOM LOG */}
      <div style={{position:"absolute",bottom:0,left:0,right:0,height:102,zIndex:20}}>
        <Glass style={{position:"absolute",inset:0,margin:"0 14px 10px",padding:"8px 14px",display:"flex",flexDirection:"column"}}>
          <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:4,flexShrink:0}}>
            <div style={{fontSize:8,fontWeight:700,color:"rgba(255,255,255,.4)",letterSpacing:2}}>SYSTEM LOG</div>
            <div style={{fontSize:7,color:"rgba(255,255,255,.2)"}}>{logs.length} entries</div>
          </div>
          <div style={{flex:1,overflowY:"auto"}}>
            {logs.length===0?(
              <div style={{fontSize:8,color:"rgba(255,255,255,.12)",padding:"6px 0"}}>{mode==="normal"?"All systems nominal":"Monitoring..."}</div>
            ):(
              logs.map((l,i)=>{
                const lc={WARN:"#ffaa00",ALERT:"#ff3c3c",CRITICAL:"#ff3c3c"}[l.lv]||"#00e6a0";
                return(
                  <div key={`${l.t}-${i}`} style={{display:"flex",gap:8,padding:"3px 0",borderBottom:"1px solid rgba(255,255,255,.02)",animation:"logS .4s ease"}}>
                    <span style={{fontSize:7.5,color:"rgba(255,255,255,.2)",flexShrink:0,width:50}}>[{l.time}]</span>
                    <span style={{fontSize:7,fontWeight:700,color:lc,flexShrink:0,width:48,letterSpacing:1}}>{l.lv}</span>
                    <span style={{fontSize:8,color:"rgba(255,255,255,.55)"}}>{l.msg}</span>
                  </div>
                );
              })
            )}
          </div>
        </Glass>
      </div>

      {hasAlert&&<div style={{position:"absolute",inset:4,zIndex:50,pointerEvents:"none",border:"2px solid #ff3c3c",borderRadius:10,animation:"aF .8s ease-in-out infinite"}}/>}
    </div>
  );
}
